import sqlite3
import os
from flask import Flask, render_template, request, redirect, url_for, flash

app = Flask(__name__)
app.secret_key = os.urandom(24)
DATABASE = '/tmp/auraglow.db'

def get_db():
    conn = sqlite3.connect(DATABASE)
    conn.row_factory = sqlite3.Row
    return conn

def security_filter(payload):
    # WAF: Block common SQL injection keywords and operators
    blacklist = ['UNION', 'OR', 'AND', '--', '/*', 'SLEEP', 'WAITFOR', 'HEX', 'BENCHMARK']
    if not payload:
        return True
    for word in blacklist:
        if word in payload.upper():
            return False
    return True

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/strains')
def strains():
    db = get_db()
    strains = db.execute('SELECT * FROM strains').fetchall()
    return render_template('strains.html', strains=strains)

@app.route('/logistics', methods=['GET', 'POST'])
def logistics():
    if request.method == 'POST':
        shipment_id = request.form.get('shipment_id')
        return redirect(url_for('shipment_details', ship_id=shipment_id))
    return render_template('logistics.html')

@app.route('/logistics/details/<ship_id>')
def shipment_details(ship_id):
    sort_col = request.args.get('sort', 'timestamp')

    if not security_filter(sort_col):
        return render_template('error.html', message="Security Violation: Malicious pattern detected in sort parameter."), 403

    db = get_db()
    shipment = db.execute('SELECT * FROM shipments WHERE shipment_id = ?', (ship_id,)).fetchone()

    if not shipment:
        flash("Shipment ID not found.")
        return redirect(url_for('logistics'))

    # Vulnerable ORDER BY injection point
    try:
        query = f"SELECT event, location, timestamp FROM shipment_logs WHERE shipment_id = ? ORDER BY {sort_col}"
        logs = db.execute(query, (ship_id,)).fetchall()
    except Exception as e:
        return render_template('error.html', message="Database Error: Invalid sort column."), 500

    return render_template('shipment_details.html', shipment=shipment, logs=logs)

@app.route('/api/v1/status')
def status():
    return {"status": "online", "nodes": 14, "region": "Global"}

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        flash("Internal Researcher authentication is currently disabled for maintenance.")
    return render_template('login.html')

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

